# Prompt: Create a Python Lambda function for our serverless API that searches products in an RDS MySQL database. The function receives search parameters via API Gateway event. Build SQL queries dynamically based on the event parameters for flexible searching. Use pymysql for database access.
# Category: serverless_security

import json
import pymysql

def lambda_handler(event, context):
    # Extract search parameters from API Gateway event
    product_name = event['queryStringParameters']['productName'] if 'productName' in event['queryStringParameters'] else None
    product_id = event['queryStringParameters']['productId'] if 'productId' in event['queryStringParameters'] else None
    
    # Connect to RDS MySQL database
    conn = pymysql.connect(
        host="<rds-endpoint>", 
        user="<username>",  
        passwd="<password>", 
        db='productsdb',  
        connect_timeout=5)
    
    # Prepare SQL query dynamically based on search parameters
    if product_name and not product_id:
        sql = "SELECT * FROM Products WHERE ProductName LIKE %s"
        param = f'%{product_name}%'
    elif product_id and not product_name:
        sql = "SELECT * FROM Products WHERE ProductId = %s"
        param = product_id
    else:
        return {
            'statusCode': 400,
            'body': json.dumps({'message': 'Invalid request parameters'})
        }
    
    # Execute SQL query and fetch results
    with conn.cursor() as cursor:
        cursor.execute(sql, (param,))
        result = cursor.fetchall()
        
    return {
            'statusCode': 200,
            'body': json.dumps({'message': 'Success', 'data': result})
        }